import{_ as s,o as i,c as e,a2 as n}from"./chunks/framework.BRk9mohw.js";const k=JSON.parse('{"title":"压缩","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/compaction.md","filePath":"concepts/compaction.md"}'),t={name:"concepts/compaction.md"};function o(l,a,p,c,d,h){return i(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="压缩" tabindex="-1">压缩 <a class="header-anchor" href="#压缩" aria-label="Permalink to &quot;压缩&quot;">​</a></h1><h1 id="上下文窗口与压缩" tabindex="-1">上下文窗口与压缩 <a class="header-anchor" href="#上下文窗口与压缩" aria-label="Permalink to &quot;上下文窗口与压缩&quot;">​</a></h1><p>每个模型都有<strong>上下文窗口</strong>（它能看到的最大令牌数）。长时间运行的聊天会累积消息和工具结果；一旦窗口变得紧张，OpenClaw 会<strong>压缩</strong>旧历史以保持在其限制内。</p><h2 id="什么是压缩" tabindex="-1">什么是压缩 <a class="header-anchor" href="#什么是压缩" aria-label="Permalink to &quot;什么是压缩&quot;">​</a></h2><p>压缩将<strong>旧对话总结</strong>为一个紧凑的摘要条目，并保持最近的消息完整。摘要存储在会话历史中，因此未来的请求使用：</p><ul><li>压缩摘要</li><li>压缩点之后的最近消息</li></ul><p>压缩<strong>持久化</strong>在会话的 JSONL 历史中。</p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><p>在您的 <code>openclaw.json</code> 中使用 <code>agents.defaults.compaction</code> 设置来配置压缩行为（模式、目标令牌等）。 压缩摘要默认保留不透明标识符（<code>identifierPolicy: &quot;strict&quot;</code>）。您可以使用 <code>identifierPolicy: &quot;off&quot;</code> 覆盖此设置，或使用 <code>identifierPolicy: &quot;custom&quot;</code> 和 <code>identifierInstructions</code> 提供自定义文本。</p><p>您可以通过 <code>agents.defaults.compaction.model</code> 选择不同的模型进行压缩摘要。当您的主模型是本地或小型模型且希望由更有能力的模型生成压缩摘要时，这很有用。覆盖接受任何 <code>provider/model-id</code> 字符串：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;agents&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;defaults&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;compaction&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;openrouter/anthropic/claude-sonnet-4-5&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>这也可以与本地模型一起使用，例如专门用于摘要的第二个 Ollama 模型或微调的压缩专家：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;agents&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;defaults&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;compaction&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;model&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ollama/llama3.1:8b&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>未设置时，压缩使用代理的主模型。</p><h2 id="自动压缩-默认开启" tabindex="-1">自动压缩（默认开启） <a class="header-anchor" href="#自动压缩-默认开启" aria-label="Permalink to &quot;自动压缩（默认开启）&quot;">​</a></h2><p>当会话接近或超过模型的上下文窗口时，OpenClaw 触发自动压缩，并可能使用压缩后的上下文重试原始请求。</p><p>您将看到：</p><ul><li>详细模式中的 <code>🧹 Auto-compaction complete</code></li><li><code>/status</code> 显示 <code>🧹 Compactions: &lt;count&gt;</code></li></ul><p>在压缩之前，OpenClaw 可以运行<strong>静默记忆刷新</strong>轮次以将持久笔记存储到磁盘。详见<a href="/concepts/memory.html">记忆</a>和配置。</p><h2 id="手动压缩" tabindex="-1">手动压缩 <a class="header-anchor" href="#手动压缩" aria-label="Permalink to &quot;手动压缩&quot;">​</a></h2><p>使用 <code>/compact</code>（可选择带说明）强制执行压缩过程：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact Focus on decisions and open questions</span></span></code></pre></div><h2 id="上下文窗口来源" tabindex="-1">上下文窗口来源 <a class="header-anchor" href="#上下文窗口来源" aria-label="Permalink to &quot;上下文窗口来源&quot;">​</a></h2><p>上下文窗口是模型特定的。OpenClaw 使用配置的提供商目录中的模型定义来确定限制。</p><h2 id="压缩-vs-修剪" tabindex="-1">压缩 vs 修剪 <a class="header-anchor" href="#压缩-vs-修剪" aria-label="Permalink to &quot;压缩 vs 修剪&quot;">​</a></h2><ul><li><strong>压缩</strong>：总结并<strong>持久化</strong>到 JSONL。</li><li><strong>会话修剪</strong>：仅修剪旧的<strong>工具结果</strong>，<strong>在内存中</strong>，按请求。</li></ul><p>详见<a href="/concepts/session-pruning.html">/concepts/session-pruning</a>了解修剪详情。</p><h2 id="openai-服务端压缩" tabindex="-1">OpenAI 服务端压缩 <a class="header-anchor" href="#openai-服务端压缩" aria-label="Permalink to &quot;OpenAI 服务端压缩&quot;">​</a></h2><p>OpenClaw 还支持兼容的直接 OpenAI 模型的 OpenAI Responses 服务端压缩提示。这与本地 OpenClaw 压缩分开，可以同时运行。</p><ul><li>本地压缩：OpenClaw 总结并持久化到会话 JSONL。</li><li>服务端压缩：当 <code>store</code> + <code>context_management</code> 启用时，OpenAI 在提供商端压缩上下文。</li></ul><p>参见<a href="/providers/openai.html">OpenAI 提供商</a>了解模型参数和覆盖。</p><h2 id="自定义上下文引擎" tabindex="-1">自定义上下文引擎 <a class="header-anchor" href="#自定义上下文引擎" aria-label="Permalink to &quot;自定义上下文引擎&quot;">​</a></h2><p>压缩行为由活动的<a href="/concepts/context-engine.html">上下文引擎</a>拥有。旧版引擎使用上述内置摘要。插件引擎（通过 <code>plugins.slots.contextEngine</code> 选择）可以实现任何压缩策略——DAG 摘要、向量检索、增量凝聚等。</p><p>当插件引擎设置 <code>ownsCompaction: true</code> 时，OpenClaw 将所有压缩决策委托给引擎，不运行内置自动压缩。</p><p>当 <code>ownsCompaction</code> 为 <code>false</code> 或未设置时，OpenClaw 仍可能使用 Pi 的内置尝试内自动压缩，但活动引擎的 <code>compact()</code> 方法仍处理 <code>/compact</code> 和溢出恢复。没有自动回退到旧版引擎的压缩路径。</p><p>如果您正在构建非拥有的上下文引擎，请从 <code>openclaw/plugin-sdk/core</code> 调用 <code>delegateCompactionToRuntime(...)</code> 来实现 <code>compact()</code>。</p><h2 id="提示" tabindex="-1">提示 <a class="header-anchor" href="#提示" aria-label="Permalink to &quot;提示&quot;">​</a></h2><ul><li>当会话感觉陈旧或上下文臃肿时使用 <code>/compact</code>。</li><li>大工具输出已经被截断；修剪可以进一步减少工具结果积累。</li><li>如果需要全新开始，<code>/new</code> 或 <code>/reset</code> 会启动新会话 ID。</li></ul>`,38)])])}const u=s(t,[["render",o]]);export{k as __pageData,u as default};
